function formatCountdown(ms) {
    if (ms <= 0) return {
        h: "00",
        m: "00",
        s: "00",
        total: 0
    };
    const total = Math.floor(ms / 1000);
    const h = Math.floor(total / 3600);
    const m = Math.floor(total % 3600 / 60);
    const s = total % 60;
    return {
        h: String(h).padStart(2, "0"),
        m: String(m).padStart(2, "0"),
        s: String(s).padStart(2, "0"),
        total
    };
}
